import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting buffer size to prevent buffer overflow
        byte[] buffer = new byte[10]; // Buffer size is limited to 10 bytes

        // Copy user input into the buffer with proper length validation
        byte[] userInputBytes = name.getBytes();

        if (userInputBytes.length <= buffer.length) {
            System.arraycopy(userInputBytes, 0, buffer, 0, userInputBytes.length);
            System.out.println("Welcome, " + new String(buffer));
        } else {
            System.out.println("Input exceeds buffer size. Please enter a shorter name.");
            // You can choose to truncate the input or handle it in another appropriate way
        }
    }
}

